SELECT c.city_name AS City, c.population AS Population, s.state_name AS State, c.elevation AS Elevation
FROM cities c
JOIN states s ON c.state_id = s.state_id
WHERE c.population = (
    SELECT MAX(population) FROM cities
);

SELECT city_name 
FROM cities 
ORDER BY city_name;

SELECT city_id, analysis_summary
FROM weather_analysis
WHERE state_id = 0;

SELECT city_name, population
FROM cities
WHERE population > (SELECT AVG(population) FROM cities);

SELECT DISTINCT c.city_name
FROM cities c
INNER JOIN weather_analysis w ON c.city_id = w.city_id;
